import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Booking() {
  const [bookings, setBookings] = useState([]);
  const [userName, setUserName] = useState("");
  const [serviceName, setServiceName] = useState("");

  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/");
    }

    axios.get("http://localhost:5000/api/bookings")
      .then(res => setBookings(res.data));
  }, []);

  const bookService = () => {
    const token = localStorage.getItem("token");

    axios.post("http://localhost:5000/api/bookings", {
      userName,
      serviceName
    }, {
      headers: {
        authorization: token
      }
    }).then(() => {
      alert("Booked!");

      axios.get("http://localhost:5000/api/bookings")
        .then(res => setBookings(res.data));
    });
  };

  const logout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
    <div>
        
      <h2>Service Booking</h2>

      <button onClick={logout}>Logout</button>

      <input placeholder="Your Name" onChange={(e) => setUserName(e.target.value)} />
      <input placeholder="Service Name" onChange={(e) => setServiceName(e.target.value)} />

      <button onClick={bookService}>Book</button>

      <h3>All Bookings</h3>

      {bookings.map((b, i) => (
        <p key={i}>
          {b.userName} booked {b.serviceName}
        </p>
      ))}
    </div>
  );
}

export default Booking;
